{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_012RJEyJBRrfYeLeDMgECXcn","type":"tool_result","content":"     1→#!/usr/bin/env node
     2→// ClawCraft Bridge CLI — send commands to running Electron app via WebSocket
     3→// Usage: node bridge.js <action> [JSON args]
     4→// Examples:
     5→//   node bridge.js getState
     6→//   node bridge.js createAgent '{"engine":"claude","name":"Claude-01"}'
     7→//   node bridge.js startRun '{"agentId":"1","prompt":"Fix the bug in app.js"}'
     8→//   node bridge.js listAgents
     9→//   node bridge.js getDiff 1
    10→//   node bridge.js removeAgent 1
    11→
    12→const WebSocket = require('ws');
    13→const BRIDGE_URL = 'ws://localhost:9477';
    14→
    15→const action = process.argv[2];
    16→if (!action) {
    17→  console.log('Usage: node bridge.js <action> [args]');
    18→  console.log('Actions: getState, listAgents, createAgent, removeAgent, startRun, cancelRun, startRelay, getDiff');
    19→  process.exit(1);
    20→}
    21→
    22→const arg = process.argv[3];
    23→let payload, agentId, runId;
    24→
    25→try {
    26→  if (action === 'removeAgent' || action === 'getDiff') {
    27→    agentId = arg;
    28→  } else if (action === 'cancelRun') {
    29→    runId = arg;
    30→  } else if (arg) {
    31→    payload = JSON.parse(arg);
    32→  }
    33→} catch {
    34→  payload = { prompt: arg };
    35→}
    36→
    37→const ws = new WebSocket(BRIDGE_URL);
    38→const msgId = Date.now().toString();
    39→
    40→ws.on('open', () => {
    41→  const msg = { id: msgId, action };
    42→  if (payload) msg.payload = payload;
    43→  if (agentId) msg.agentId = agentId;
    44→  if (runId) msg.runId = runId;
    45→  ws.send(JSON.stringify(msg));
    46→});
    47→
    48→ws.on('message', (raw) => {
    49→  const data = JSON.parse(raw);
    50→  if (data.type === 'connected') return;
    51→  if (data.type === 'response' && data.id === msgId) {
    52→    console.log(JSON.stringify(data.result, null, 2));
    53→    ws.close();
    54→  }
    55→  if (data.type === 'error' && data.id === msgId) {
    56→    console.error('Error:', data.error);
    57→    ws.close();
    58→    process.exit(1);
    59→  }
    60→  if (data.type === 'event') {
    61→    // Stream events if waiting
    62→    const e = data.event;
    63→    if (e.type === 'run.phase') process.stderr.write(`[${e.phase}] ${e.label || ''} ${Math.round((e.progress||0)*100)}%\n`);
    64→    if (e.type === 'run.output') process.stderr.write(`[output] ${e.text?.slice(0,200)}\n`);
    65→    if (e.type === 'run.completed') { console.log('\n✅ Run completed'); ws.close(); }
    66→    if (e.type === 'run.failed') { console.error('\n❌ Run failed:', e.errorText); ws.close(); process.exit(1); }
    67→  }
    68→});
    69→
    70→ws.on('error', (err) => {
    71→  console.error('Connection failed. Is ClawCraft Electron app running? (npm start)');
    72→  console.error(err.message);
    73→  process.exit(1);
    74→});
    75→
    76→// Timeout
    77→setTimeout(() => { console.error('Timeout'); ws.close(); process.exit(1); }, 30000);
    78→"}]},"parent_tool_use_id":"toolu_01AbM6BEmMsVd97JEuiPjngR","session_id":"3fe55042-d602-468a-902b-d4039d503a70","uuid":"978e1aad-79ac-4940-8673-a1f3729a3c47"}

