    44→function applyRunToAgent(event){
    45→  const agent=findAgent(event.agentId||event.run?.agentId);
    46→  if(!agent)return;
    47→  if(event.type==='run.started'){
    48→    agent.beginLiveRun(event.run);
    49→    openTaskDrawer(agent.id);
    50→    return;
    51→  }
    52→  if(event.type==='run.phase'){
    53→    agent.applyRunPhase(event.phase,event.progress,event.label);
    54→    return;
    55→  }
    56→  if(event.type==='run.output'){
    57→    agent.applyRunPhase(event.phase,event.progress,agent.runLabel);
    58→    agent.appendRunLog(event.text);
    59→    return;
    60→  }
    61→  if(event.type==='run.completed'){
    62→    agent.finishRun('done',event.run);
    63→    return;
    64→  }
    65→  if(event.type==='run.failed'){
    66→    agent.errorText=event.errorText||'실패';
    67→    agent.appendRunLog(`ERROR: ${agent.errorText}`);
    68→    agent.finishRun('failed',event.run);
    69→    return;
    70→  }
    71→  if(event.type==='run.cancelled'){
    72→    agent.finishRun('cancelled',event.run);
    73→  }
    74→}
